-- Seed: Document Retention Rules sourced from Federal and California law
-- Each rule cites the actual statute, regulation, or requirement

-- ============================================================
-- FEDERAL TAX RECORDS (IRS)
-- ============================================================

INSERT OR IGNORE INTO retention_rules (id, title, description, document_types, retention_years, retention_months, retention_from, basis, legal_citation, jurisdiction, purposes, storage_requirements, disposal_method, applies_to_entity_types, applies_to_industries, penalty_for_non_compliance, notes, is_active, effective_date, source_url)
VALUES
('RET-FED-TAX-001', 'Federal Tax Returns', 'Business income tax returns and supporting documentation must be retained for the period of limitations on filing amendments or claiming refunds.', '["TAX_RETURN","FINANCIAL_STATEMENT"]', 3, 0, 'TAX_YEAR_END', 'FEDERAL_STATUTE', '26 USC § 6501(a) — Statute of limitations for assessment', 'FEDERAL', '["TAX_AUDIT","LEGAL_COMPLIANCE"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'IRS may assess additional tax within 3 years; extends to 6 years if >25% gross income omitted (§ 6501(e)); no limit for fraud (§ 6501(c))', 'Keep 7 years as best practice to cover the 6-year substantial omission rule plus buffer', 1, '1954-08-16', 'https://www.law.cornell.edu/uscode/text/26/6501'),

('RET-FED-TAX-002', 'Employment Tax Records', 'Records of employment taxes (941, 940, W-2, W-4) must be available for IRS review for at least 4 years after the tax becomes due or is paid, whichever is later.', '["TAX_RETURN","W9","TRAINING_RECORD"]', 4, 0, 'TAX_YEAR_END', 'FEDERAL_REGULATION', '26 CFR § 31.6001-1 — Records of employers', 'FEDERAL', '["TAX_AUDIT","EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'Failure to maintain: penalty under IRC § 6721-6722, up to $290 per return (2024)', 'Includes Forms W-2, W-4, 941, 940, 1099 series', 1, '1954-08-16', 'https://www.law.cornell.edu/cfr/text/26/section-31.6001-1'),

('RET-FED-TAX-003', 'Asset and Depreciation Records', 'Records supporting the cost basis, depreciation, and disposition of business assets must be kept until the period of limitations expires for the year of disposition.', '["FINANCIAL_STATEMENT","TAX_RETURN"]', 7, 0, 'LAST_ACTION_DATE', 'FEDERAL_STATUTE', '26 USC § 6001 — Records and returns generally', 'FEDERAL', '["TAX_AUDIT","LEGAL_COMPLIANCE"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'Inability to substantiate basis may result in zero basis assignment and full gain recognition', 'Keep for life of asset plus 3-7 years after disposition', 1, '1954-08-16', 'https://www.law.cornell.edu/uscode/text/26/6001'),

-- ============================================================
-- FEDERAL EMPLOYMENT RECORDS
-- ============================================================

('RET-FED-EMP-001', 'FLSA Payroll Records', 'Fair Labor Standards Act requires employers to preserve payroll records, collective bargaining agreements, sales and purchase records for at least 3 years.', '["FINANCIAL_STATEMENT","EMPLOYEE_HANDBOOK"]', 3, 0, 'LAST_ACTION_DATE', 'FEDERAL_STATUTE', '29 USC § 211(c); 29 CFR § 516.5 — FLSA Records to be preserved', 'FEDERAL', '["EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE","REGULATORY_AUDIT"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'WHD investigation; back wages up to 2 years (3 years for willful); liquidated damages equal to back wages', 'Includes basic payroll data: name, address, DOB, sex, occupation, time/day workweek begins, hours per day/week, rate of pay, deductions, wages paid', 1, '1938-06-25', 'https://www.law.cornell.edu/cfr/text/29/section-516.5'),

('RET-FED-EMP-002', 'FLSA Supplementary Records', 'Wage computation records, time cards, piece work tickets, order/shipping records must be preserved for 2 years.', '["TRAINING_RECORD"]', 2, 0, 'LAST_ACTION_DATE', 'FEDERAL_REGULATION', '29 CFR § 516.6 — Records to be preserved 2 years', 'FEDERAL', '["EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'Same as FLSA payroll records — WHD investigation and back pay liability', 'Time cards, wage rate tables, work schedules, order/shipping/billing records', 1, '1938-06-25', 'https://www.law.cornell.edu/cfr/text/29/section-516.6'),

('RET-FED-EMP-003', 'Title VII / ADA / GINA Personnel Records', 'Employers with 15+ employees must keep all personnel and employment records for 1 year from date of making the record or personnel action, whichever is later.', '["EMPLOYEE_HANDBOOK","TRAINING_RECORD","ANTI_HARASSMENT_POLICY"]', 1, 0, 'CREATION_DATE', 'FEDERAL_REGULATION', '29 CFR § 1602.14 — Preservation of records made or kept', 'FEDERAL', '["EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE","LITIGATION_READINESS"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'EEOC investigation; Title VII allows compensatory + punitive damages up to $300K; ADA same', 'If charge filed, preserve all records until final disposition. Extends to 2 years for federal contractors (EO 11246)', 1, '1964-07-02', 'https://www.law.cornell.edu/cfr/text/29/section-1602.14'),

('RET-FED-EMP-004', 'ADEA Age Discrimination Records', 'Payroll records under ADEA must be preserved for 3 years; personnel records related to hiring, promotion, demotion, transfer, layoff, termination for 1 year.', '["EMPLOYEE_HANDBOOK","TRAINING_RECORD"]', 3, 0, 'CREATION_DATE', 'FEDERAL_REGULATION', '29 CFR § 1627.3 — Records to be made or kept', 'FEDERAL', '["EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE","LITIGATION_READINESS"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'Liquidated damages (double back pay) for willful violations; EEOC enforcement', 'Employee benefit plans and seniority/merit systems: keep for full period plan is in effect plus 1 year after termination', 1, '1967-12-15', 'https://www.law.cornell.edu/cfr/text/29/section-1627.3'),

('RET-FED-EMP-005', 'FMLA Leave Records', 'Family and Medical Leave Act records including leave dates, hours, notices, policies, premium payments must be kept for 3 years.', '["EMPLOYEE_HANDBOOK","TRAINING_RECORD"]', 3, 0, 'CREATION_DATE', 'FEDERAL_REGULATION', '29 CFR § 825.500 — Recordkeeping requirements', 'FEDERAL', '["EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE"]', '["DIGITAL_ACCEPTABLE","ENCRYPTED_STORAGE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'WHD enforcement; back pay, benefits restoration, liquidated damages, attorney fees', 'Medical certifications must be maintained in separate confidential files (ADA requirement)', 1, '1993-02-05', 'https://www.law.cornell.edu/cfr/text/29/section-825.500'),

('RET-FED-EMP-006', 'I-9 Employment Eligibility', 'Form I-9 must be retained for 3 years after date of hire or 1 year after employment ends, whichever is later.', '["OTHER"]', 3, 0, 'CREATION_DATE', 'FEDERAL_STATUTE', '8 USC § 1324a(b)(3) — Retention of verification form; 8 CFR § 274a.2', 'FEDERAL', '["EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE","REGULATORY_AUDIT"]', '["DIGITAL_ACCEPTABLE","TAMPER_EVIDENT"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'Civil penalties $252-$2,507 per I-9 violation (2024); pattern violations: criminal penalties', 'E-Verify records follow same retention. Must be available within 3 days of ICE inspection request.', 1, '1986-11-06', 'https://www.law.cornell.edu/uscode/text/8/1324a'),

