-- FEDERAL SAFETY (OSHA)
-- ============================================================

('RET-FED-OSHA-001', 'OSHA Injury/Illness Records', 'OSHA 300, 300A, and 301 forms must be retained for 5 years following the end of the calendar year the records cover.', '["SAFETY_PLAN","TRAINING_RECORD"]', 5, 0, 'TAX_YEAR_END', 'FEDERAL_REGULATION', '29 CFR § 1904.33 — Retention and updating of old OSHA 300 Logs', 'FEDERAL', '["LEGAL_COMPLIANCE","REGULATORY_AUDIT","EMPLOYMENT_RECORDS"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'Citations up to $16,131 per violation; willful: up to $161,323 (2024)', 'Employers with 10 or fewer employees in most industries are exempt from routine recordkeeping', 1, '1970-12-29', 'https://www.law.cornell.edu/cfr/text/29/section-1904.33'),

('RET-FED-OSHA-002', 'OSHA Exposure/Medical Records', 'Employee exposure and medical records related to toxic substances or harmful physical agents must be retained for duration of employment plus 30 years.', '["SAFETY_PLAN","TRAINING_RECORD"]', 30, 0, 'EMPLOYEE_SEPARATION', 'FEDERAL_REGULATION', '29 CFR § 1910.1020 — Access to employee exposure and medical records', 'FEDERAL', '["LEGAL_COMPLIANCE","EMPLOYMENT_RECORDS","LITIGATION_READINESS"]', '["DIGITAL_ACCEPTABLE","ENCRYPTED_STORAGE","OFFSITE_BACKUP"]', 'ARCHIVE_THEN_DESTROY', '"ALL"', '"ALL"', 'Citations; also used as evidence in toxic tort litigation with extended statutes of limitations', 'This is the longest mandatory retention period in federal employment law. Transfer records if business closes.', 1, '1970-12-29', 'https://www.law.cornell.edu/cfr/text/29/section-1910.1020'),

