-- FEDERAL CORPORATE/FINANCIAL
-- ============================================================

('RET-FED-CORP-001', 'SOX Financial Records', 'Sarbanes-Oxley requires retention of audit work papers and records relevant to the audit or review for 7 years from the conclusion of the audit or review.', '["AUDIT_REPORT","FINANCIAL_STATEMENT","SOC2_REPORT"]', 7, 0, 'AUDIT_COMPLETION', 'FEDERAL_STATUTE', '15 USC § 7213(a)(2)(A)(i) — SOX § 802; 18 USC § 1520', 'FEDERAL', '["LEGAL_COMPLIANCE","REGULATORY_AUDIT","LITIGATION_READINESS"]', '["DIGITAL_WITH_AUDIT_TRAIL","TAMPER_EVIDENT"]', 'SECURE_DELETE', '["CORPORATION","S_CORP"]', '"ALL"', 'Criminal: up to 20 years imprisonment and fines for knowing destruction (18 USC § 1520)', 'Applies to public companies and their auditors. Private companies should follow as best practice.', 1, '2002-07-30', 'https://www.law.cornell.edu/uscode/text/18/1520'),

('RET-FED-CORP-002', 'BOI Reports', 'Beneficial Ownership Information reports filed with FinCEN. FinCEN retains; filers should keep copies of what was submitted.', '["BOI_REPORT"]', 5, 0, 'FILING_DATE', 'FEDERAL_STATUTE', '31 USC § 5336 — Corporate Transparency Act; 31 CFR § 1010.380', 'FEDERAL', '["LEGAL_COMPLIANCE","REGULATORY_AUDIT"]', '["DIGITAL_ACCEPTABLE","ENCRYPTED_STORAGE"]', 'SECURE_DELETE', '["LLC","CORPORATION","S_CORP","PARTNERSHIP"]', '"ALL"', 'Civil penalties up to $591/day; criminal: up to 2 years imprisonment and $10,000 fine', 'Must update within 30 days of any change in beneficial owner information', 1, '2024-01-01', 'https://www.law.cornell.edu/uscode/text/31/5336'),

('RET-FED-CORP-003', 'Corporate Formation Documents', 'Articles of incorporation, bylaws, operating agreements, and amendments should be retained permanently as foundational governance documents.', '["ARTICLES_OF_INCORPORATION","BYLAWS","OPERATING_AGREEMENT"]', 0, 0, 'PERMANENT', 'BEST_PRACTICE', 'State corporation codes; UCC; common law fiduciary duty', 'FEDERAL', '["LEGAL_COMPLIANCE","LITIGATION_READINESS","REFERENCE","HISTORICAL"]', '["DIGITAL_WITH_AUDIT_TRAIL","CERTIFIED_COPY"]', 'NO_DESTRUCTION', '"ALL"', '"ALL"', 'Inability to produce may result in piercing corporate veil, loss of liability protection', 'Keep permanently. These prove the entity exists and define its governance.', 1, '1800-01-01', ''),

