-- FEDERAL PRIVACY
-- ============================================================

('RET-FED-PRIV-001', 'Privacy Policy Records', 'Records of privacy policies, consent forms, and data processing agreements should be retained for the duration of any applicable statute of limitations on privacy claims.', '["PRIVACY_POLICY","DATA_PROCESSING_AGREEMENT"]', 6, 0, 'LAST_ACTION_DATE', 'BEST_PRACTICE', 'FTC Act § 5; COPPA; state privacy laws (CCPA/CPRA Cal. Civ. Code § 1798.100 et seq.)', 'FEDERAL', '["LEGAL_COMPLIANCE","LITIGATION_READINESS","REGULATORY_AUDIT"]', '["DIGITAL_WITH_AUDIT_TRAIL"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'FTC enforcement actions; state AG enforcement; private right of action under CCPA', 'Keep ALL versions of privacy policies with effective dates. Critical for litigation defense.', 1, '2000-04-21', ''),

