-- ============================================================

('RET-FED-CON-001', 'Government Contract Records', 'Federal contractors must retain records for 3 years after final payment on the contract.', '["CONTRACT","FINANCIAL_STATEMENT","AUDIT_REPORT"]', 3, 0, 'CONTRACT_EXPIRATION', 'FEDERAL_REGULATION', '48 CFR § 4.703 — FAR Subpart 4.7 Contractor Records Retention', 'FEDERAL', '["LEGAL_COMPLIANCE","REGULATORY_AUDIT","LITIGATION_READINESS"]', '["DIGITAL_WITH_AUDIT_TRAIL"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'False Claims Act liability (31 USC § 3729): treble damages plus $13,508-$27,018 per claim', 'If audit or investigation is pending, records must be retained until resolution regardless of 3-year rule', 1, '1984-04-01', 'https://www.law.cornell.edu/cfr/text/48/section-4.703'),

