('RET-CA-EMP-001', 'CA Payroll Records', 'California employers must keep payroll records for at least 4 years (covers the 4-year statute of limitations for wage claims under CCP § 337).', '["FINANCIAL_STATEMENT"]', 4, 0, 'CREATION_DATE', 'STATE_STATUTE', 'Cal. Lab. Code § 1174; CCP § 337; IWC Wage Orders', 'CA', '["EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE","LITIGATION_READINESS"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'PAGA penalties: $100/employee first violation, $200/employee subsequent; waiting time penalties: up to 30 days wages', 'CA has longer retention than federal (4 vs 3 years) — always follow the longer requirement', 1, '1937-01-01', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=1174&lawCode=LAB'),

('RET-CA-EMP-002', 'CA Personnel Files', 'California employers must retain personnel files for at least 3 years after separation (Lab. Code § 1198.5 access right lasts through employment).', '["EMPLOYEE_HANDBOOK","TRAINING_RECORD","ANTI_HARASSMENT_POLICY"]', 3, 0, 'EMPLOYEE_SEPARATION', 'STATE_STATUTE', 'Cal. Lab. Code § 1198.5; FEHA (Gov. Code § 12946)', 'CA', '["EMPLOYMENT_RECORDS","LEGAL_COMPLIANCE","LITIGATION_READINESS"]', '["DIGITAL_ACCEPTABLE","ENCRYPTED_STORAGE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'FEHA: unlimited compensatory damages, punitive damages, attorney fees; DFEH investigation', 'FEHA requires 4 years for discrimination-related records. Use 4 years as safe harbor.', 1, '1959-09-18', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=12946&lawCode=GOV'),

('RET-CA-TAX-001', 'CA Franchise Tax Board Records', 'California tax returns and supporting records should be kept for at least 4 years (FTB statute of limitations under R&TC § 19057).', '["TAX_RETURN","FINANCIAL_STATEMENT"]', 4, 0, 'TAX_YEAR_END', 'STATE_STATUTE', 'Cal. Rev. & Tax Code § 19057; § 19501', 'CA', '["TAX_AUDIT","LEGAL_COMPLIANCE"]', '["DIGITAL_ACCEPTABLE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'FTB penalties: 5-25% of tax due for late filing; fraud: 75% penalty', 'If return not filed, no statute of limitations — keep records permanently for unfiled years', 1, '1929-01-01', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=19057&lawCode=RTC'),

('RET-CA-PRIV-001', 'CCPA/CPRA Consumer Request Records', 'Businesses must maintain records of consumer requests and how they were responded to for at least 24 months.', '["PRIVACY_POLICY","DATA_PROCESSING_AGREEMENT","OTHER"]', 2, 0, 'CREATION_DATE', 'STATE_STATUTE', 'Cal. Civ. Code § 1798.130; 11 CCR § 7101', 'CA', '["LEGAL_COMPLIANCE","REGULATORY_AUDIT","PRIVACY"]', '["DIGITAL_WITH_AUDIT_TRAIL","ENCRYPTED_STORAGE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'CPPA enforcement: up to $2,500/violation, $7,500/intentional violation; private right of action for data breaches: $100-$750/consumer/incident', 'Must track: date of request, nature, manner of response, basis for denial if applicable', 1, '2020-01-01', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=1798.130&lawCode=CIV'),

('RET-CA-CORP-001', 'CA Annual Statements of Information', 'Copies of Statements of Information (SI-100, SI-550) filed with CA Secretary of State should be retained permanently.', '["ANNUAL_REPORT","COMPLIANCE_CERTIFICATE"]', 0, 0, 'PERMANENT', 'STATE_STATUTE', 'Cal. Corp. Code § 1502 (corporations); § 17702.09 (LLCs)', 'CA', '["LEGAL_COMPLIANCE","REFERENCE","HISTORICAL"]', '["DIGITAL_ACCEPTABLE"]', 'NO_DESTRUCTION', '["LLC","CORPORATION","S_CORP","NONPROFIT","COOPERATIVE"]', '"ALL"', '$250 penalty for late filing (Corp. Code § 2204); may lead to suspension/forfeiture by FTB', 'Due within 90 days of formation, then every year (LLCs biennial). Filed via bizfile.sos.ca.gov.', 1, '1977-01-01', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=1502&lawCode=CORP'),

('RET-CA-INS-001', 'CA Workers Compensation Records', 'Workers compensation records, including injury reports and claim files, must be retained for 5 years after injury (or longer if claim is pending).', '["INSURANCE_CERTIFICATE","SAFETY_PLAN"]', 5, 0, 'CLAIM_RESOLUTION', 'STATE_STATUTE', 'Cal. Lab. Code § 6410; 8 CCR § 14300.33', 'CA', '["LEGAL_COMPLIANCE","INSURANCE_CLAIMS","LITIGATION_READINESS"]', '["DIGITAL_ACCEPTABLE"]', 'ARCHIVE_THEN_DESTROY', '"ALL"', '"ALL"', 'DIR penalties; WCAB jurisdiction for up to 5 years; fraud penalties under Ins. Code § 1871.4', 'Statute of limitations for WC claims: 1 year from injury or last provision of benefits', 1, '1913-01-01', 'https://leginfo.legislature.ca.gov/faces/codes_displaySection.xhtml?sectionNum=6410&lawCode=LAB'),

