-- ============================================================

('RET-GEN-001', 'Business Licenses and Permits', 'Current and historical business licenses and permits should be retained for the life of the entity plus 3 years.', '["BUSINESS_LICENSE","COMPLIANCE_CERTIFICATE"]', 0, 0, 'PERMANENT', 'BEST_PRACTICE', 'Various municipal codes; state licensing statutes', 'FEDERAL', '["LEGAL_COMPLIANCE","REFERENCE","LITIGATION_READINESS"]', '["DIGITAL_ACCEPTABLE","CERTIFIED_COPY"]', 'NO_DESTRUCTION', '"ALL"', '"ALL"', 'Operating without valid license: misdemeanor in most jurisdictions; contract voidability under Bus. & Prof. Code § 7031 (CA)', 'Keep all versions showing continuous licensing history', 1, '1800-01-01', ''),

('RET-GEN-002', 'Insurance Policies', 'All insurance policies (GL, E&O, D&O, cyber, WC) should be retained permanently or until all possible claims under the policy period have been resolved.', '["INSURANCE_CERTIFICATE"]', 0, 0, 'PERMANENT', 'BEST_PRACTICE', 'Common law; occurrence-based vs claims-made policy considerations', 'FEDERAL', '["INSURANCE_CLAIMS","LITIGATION_READINESS","LEGAL_COMPLIANCE"]', '["DIGITAL_ACCEPTABLE","OFFSITE_BACKUP"]', 'NO_DESTRUCTION', '"ALL"', '"ALL"', 'Inability to locate policy may forfeit coverage for latent claims (asbestos, environmental, long-tail torts)', 'Occurrence policies can be triggered decades later. NEVER destroy insurance policies.', 1, '1800-01-01', ''),

('RET-GEN-003', 'Contracts and Agreements', 'Executed contracts should be retained for the life of the contract plus the applicable statute of limitations (4-6 years in most states).', '["CONTRACT","DATA_PROCESSING_AGREEMENT"]', 6, 0, 'CONTRACT_EXPIRATION', 'BEST_PRACTICE', 'UCC § 2-725 (4 years goods); CCP § 337 (4 years CA written); various state SOLs', 'FEDERAL', '["LEGAL_COMPLIANCE","LITIGATION_READINESS","REFERENCE"]', '["DIGITAL_WITH_AUDIT_TRAIL"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'Inability to produce contract may result in unfavorable interpretation or inability to enforce terms', 'Include all amendments, addenda, and correspondence related to contract interpretation', 1, '1800-01-01', ''),

('RET-GEN-004', 'Meeting Minutes and Resolutions', 'Corporate/LLC meeting minutes and written resolutions should be retained permanently as part of the entity permanent record.', '["MEETING_MINUTES","RESOLUTION"]', 0, 0, 'PERMANENT', 'BEST_PRACTICE', 'State corporation codes (Cal. Corp. Code § 1500); LLC operating agreements', 'FEDERAL', '["LEGAL_COMPLIANCE","CORPORATE_GOVERNANCE","LITIGATION_READINESS","HISTORICAL"]', '["DIGITAL_WITH_AUDIT_TRAIL"]', 'NO_DESTRUCTION', '["LLC","CORPORATION","S_CORP","NONPROFIT","COOPERATIVE"]', '"ALL"', 'Failure to maintain may support veil-piercing claims; loss of limited liability protection', 'These prove the entity operates as a separate legal entity and not an alter ego', 1, '1800-01-01', ''),

('RET-GEN-005', 'EIN Assignment Letters', 'IRS EIN assignment letters (CP 575) should be retained permanently. Cannot be reissued.', '["EIN_LETTER"]', 0, 0, 'PERMANENT', 'BEST_PRACTICE', 'IRS procedures; IRC § 6109', 'FEDERAL', '["TAX_AUDIT","LEGAL_COMPLIANCE","REFERENCE"]', '["DIGITAL_ACCEPTABLE","OFFSITE_BACKUP"]', 'NO_DESTRUCTION', '"ALL"', '"ALL"', 'Without EIN letter, entity cannot open bank accounts, file taxes, or onboard with many vendors', 'The IRS does not reissue CP 575 letters. A 147C verification letter can be obtained but is not identical.', 1, '1974-01-01', ''),

