-- ============================================================

('RET-TECH-001', 'Security Incident Records', 'Records of security incidents, breach notifications, and incident response actions should be retained for at least 6 years.', '["INCIDENT_RESPONSE_PLAN","AUDIT_REPORT","PENETRATION_TEST"]', 6, 0, 'CREATION_DATE', 'BEST_PRACTICE', 'CCPA data breach provisions (Civ. Code § 1798.150); HIPAA § 164.530(j); SOX; state breach notification laws', 'FEDERAL', '["LEGAL_COMPLIANCE","LITIGATION_READINESS","REGULATORY_AUDIT","EVIDENTIARY"]', '["DIGITAL_WITH_AUDIT_TRAIL","ENCRYPTED_STORAGE","TAMPER_EVIDENT"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'CCPA: $100-$750/consumer for breach; FTC enforcement; state AG enforcement; class action exposure', 'Keep all forensic reports, notification records, remediation documentation, and regulatory correspondence', 1, '2003-07-01', ''),

('RET-TECH-002', 'System Access Logs', 'Authentication, access, and audit logs for systems containing personal or financial data should be retained for at least 1 year (3 years for financial systems).', '["AUDIT_REPORT"]', 3, 0, 'CREATION_DATE', 'INDUSTRY_STANDARD', 'PCI DSS Req. 10.7; SOC 2 Trust Services Criteria CC7.2; NIST SP 800-92', 'FEDERAL', '["LEGAL_COMPLIANCE","REGULATORY_AUDIT","EVIDENTIARY","LITIGATION_READINESS"]', '["DIGITAL_WITH_AUDIT_TRAIL","ENCRYPTED_STORAGE"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'PCI DSS non-compliance: $5,000-$100,000/month; SOC 2 audit failure; breach liability', 'Include login/logout, privilege changes, data access, admin actions, failed attempts', 1, '2004-12-15', ''),

('RET-TECH-003', 'Business Continuity and DR Plans', 'Business continuity and disaster recovery plans should be retained for the current version plus at least 3 prior versions or 5 years, whichever is longer.', '["BUSINESS_CONTINUITY_PLAN","INCIDENT_RESPONSE_PLAN"]', 5, 0, 'CREATION_DATE', 'BEST_PRACTICE', 'NIST SP 800-34; ISO 22301; state insurance department requirements', 'FEDERAL', '["LEGAL_COMPLIANCE","REFERENCE","REGULATORY_AUDIT"]', '["DIGITAL_ACCEPTABLE","OFFSITE_BACKUP"]', 'SECURE_DELETE', '"ALL"', '"ALL"', 'Insurance claim denial for failure to maintain; regulatory findings; shareholder derivative suits', 'Test results and exercise reports should be retained alongside the plans', 1, '2010-05-01', ''),

